export const CodeMirrorEditor = forwardRef<
  CodeMirrorEditorHandle,
  CodeMirrorEditorProps
>(function CodeMirrorEditor({ value, onChange, onValidationChange, isDarkMode = false }, ref) {
  const containerRef = useRef<HTMLDivElement>(null);
  const viewRef = useRef<EditorView | null>(null);
  const onChangeRef = useRef(onChange);
  const onValidationChangeRef = useRef(onValidationChange);
  const isExternalUpdate = useRef(false);

  const themeCompartment = useMemo(() => new Compartment(), []);
  const highlightCompartment = useMemo(() => new Compartment(), []);

  onChangeRef.current = onChange;
  onValidationChangeRef.current = onValidationChange;

  useImperativeHandle(ref, () => ({
    getValue: () => viewRef.current?.state.doc.toString() ?? '',
    setValue: (val: string) => {
      const view = viewRef.current;
      if (!view) return;
      isExternalUpdate.current = true;
      view.dispatch({
        changes: { from: 0, to: view.state.doc.length, insert: val },
      });
      isExternalUpdate.current = false;
    },
    getView: () => viewRef.current,
  }));

  useEffect(() => {
    if (!containerRef.current) return;

    const json5ParseLinter = linter(
      (view): Diagnostic[] => {
        const doc = view.state.doc.toString();
        if (!doc.trim()) return [];
        try {
          JSON5.parse(doc);
          onValidationChangeRef.current?.(false, null);
          return [];
        } catch (e) {
          const msg = (e as SyntaxError).message || 'Invalid JSON';
          const lineMatch = msg.match(/at (\d+):(\d+)/);
          let from = 0;
          let to = Math.min(doc.length, 1);
          if (lineMatch) {
            const line = parseInt(lineMatch[1], 10);
            const col = parseInt(lineMatch[2], 10);
            const lineInfo = view.state.doc.line(Math.min(line, view.state.doc.lines));
            from = lineInfo.from + Math.min(col - 1, lineInfo.length);
            to = Math.min(from + 1, lineInfo.to);
          }
          onValidationChangeRef.current?.(true, msg);
          return [{ from, to, severity: 'error', message: msg, source: 'json5' }];
        }
      },
      { delay: 300 },
    );

