      if (ch === strCh && (i === 0 || before[i - 1] !== '\\')) inStr = false;
      continue;
    }
    if (ch === '"' || ch === "'") { inStr = true; strCh = ch; continue; }

    if (ch === '}') depth++;
    if (ch === '{') {
