    if (before[i] === '}' || before[i] === ']') depth++;
    if (before[i] === '{' || before[i] === '[') {
      depth--;
      if (depth < 0) {
        if (before[i] === '[') {
          const preceding = before.slice(Math.max(0, i - 30), i).trim();
          return /["']body["']\s*:\s*$/.test(preceding);
        }
        const preceding = before.slice(Math.max(0, i - 30), i).trim();
        if (/,\s*$/.test(preceding) || /\[\s*$/.test(preceding)) {
          const bracketSearch = before.slice(0, i);
          const bracketPos = bracketSearch.lastIndexOf('[');
          if (bracketPos >= 0) {
            const beforeBracket = bracketSearch.slice(Math.max(0, bracketPos - 30), bracketPos).trim();
