import {
  autocompletion,
  type CompletionContext,
  type CompletionResult,
  type Completion,
} from '@codemirror/autocomplete';
import { knownTypes, componentPropsSchemas } from './sduiSchema';

interface PropSchema {
  type: string;
  properties?: Record<string, PropDef>;
  required?: readonly string[];
  enum?: readonly string[];
  nullable?: boolean;
}

interface PropDef {
  type?: string;
  enum?: readonly string[];
  nullable?: boolean;
  const?: string;
  items?: object;
}

const spacingValues = [
  'none', 'xxxs', 'xxs', 'xs', 'smaller', 'sm', 'md', 'lg', 'xl', 'xxl', 'xxxl',
];

const screenTopLevelKeys = ['id', 'context', 'header', 'body', 'footer'];

const componentStructureKeys = ['type', 'props', 'visible'];

function getTypeDescription(type: string): string {
  const descriptions: Record<string, string> = {
    heading: 'Large title text (headingMDL)',
    text: 'Configurable text with type/color/bold',
    section_heading: 'Section subtitle (subtitleXXL)',
    balance_display: 'Points balance with label and values',
    points_input: 'Numeric input field for points/reais',
    button: 'CTA button with text and optional icon',
    link: 'Pressable text link',
    alert: 'Info/warning/error alert box',
    list_text_icon: 'List of items with icon + description',
    separator: 'Horizontal line divider',
    icon_text_row: 'Row with icon and text side-by-side',
    nav_header: 'Navigation header with back button',
    rich_text: 'Inline formatted text with bold/link/icon nodes',
  };
  return descriptions[type] ?? type;
}

function getPropDetail(propName: string, propDef: PropDef): string {
  if (propDef.enum) return `enum: ${propDef.enum.join(' | ')}`;
  if (propDef.type === 'boolean') return 'boolean';
  if (propDef.type === 'number') return 'number';
  if (propDef.type === 'string') return 'string';
  if (propDef.type === 'array') return 'array';
  if (propDef.type === 'object') return 'object';
  return '';
}

function findJsonContext(doc: string, pos: number): {
  path: string[];
  inKey: boolean;
  inValue: boolean;
  currentKey: string | null;
  parentType: string | null;
} {
  const before = doc.slice(0, pos);

  const path: string[] = [];
  const stack: { key: string | null; isArray: boolean }[] = [];
  let currentKey: string | null = null;
  let inString = false;
  let stringChar = '';
  let lastKey: string | null = null;

  for (let i = 0; i < before.length; i++) {
    const ch = before[i];

    if (inString) {
      if (ch === '\\') { i++; continue; }
      if (ch === stringChar) inString = false;
      continue;
    }

    if (ch === '"' || ch === "'") {
      inString = true;
      stringChar = ch;
      continue;
    }

    if (ch === '{') {
      stack.push({ key: lastKey, isArray: false });
      lastKey = null;
    } else if (ch === '[') {
      stack.push({ key: lastKey, isArray: true });
      lastKey = null;
    } else if (ch === '}' || ch === ']') {
      stack.pop();
      lastKey = null;
    } else if (ch === ':') {
      currentKey = lastKey;
    } else if (ch === ',') {
      lastKey = null;
      currentKey = null;
    }

    if (ch === '"' || ch === "'") {
      const end = before.indexOf(ch === '"' ? '"' : "'", i + 1);
      if (end > i) {
        lastKey = before.slice(i + 1, end);
        i = end;
      }
    }
  }

  for (const frame of stack) {
    if (frame.key) path.push(frame.key);
  }

  const lineStart = before.lastIndexOf('\n') + 1;
  const line = before.slice(lineStart);
  const colonInLine = line.lastIndexOf(':');
  const inValueContext = colonInLine >= 0;
  const inKeyContext = !inValueContext;

  let parentType: string | null = null;
  const typeMatch = before.match(/"type"\s*:\s*"([^"]+)"/g);
  if (typeMatch) {
    const lastTypeMatch = typeMatch[typeMatch.length - 1];
    const typeVal = lastTypeMatch.match(/"type"\s*:\s*"([^"]+)"/);
    if (typeVal) parentType = typeVal[1];
  }

  return {
    path,
    inKey: inKeyContext,
    inValue: inValueContext,
    currentKey: currentKey || lastKey,
    parentType,
  };
}

function getComponentTypeAtCursor(doc: string, pos: number): string | null {
  const before = doc.slice(0, pos);
  let depth = 0;

  for (let i = before.length - 1; i >= 0; i--) {
    if (before[i] === '}') depth++;
    if (before[i] === '{') {
      depth--;
      if (depth < 0) {
        const chunk = before.slice(Math.max(0, i - 200), i);
        const outerBrace = chunk.lastIndexOf('{');
        if (outerBrace >= 0) {
          const outerChunk = doc.slice(Math.max(0, i - 200 + outerBrace), i + 200);
          const typeMatch = outerChunk.match(/"type"\s*:\s*"([^"]+)"/);
          if (typeMatch && (knownTypes as readonly string[]).includes(typeMatch[1])) {
            return typeMatch[1];
          }
        }
        break;
      }
    }
  }
  return null;
}

function sduiCompletionSource(context: CompletionContext): CompletionResult | null {
  const doc = context.state.doc.toString();
  const pos = context.pos;

  const beforeChar = doc.slice(Math.max(0, pos - 50), pos);

  const typeValueMatch = beforeChar.match(/"type"\s*:\s*"([^"]*)$/);
  if (typeValueMatch) {
    const prefix = typeValueMatch[1];
    const from = pos - prefix.length;
    const options: Completion[] = (knownTypes as readonly string[]).map(t => ({
      label: t,
      type: 'enum',
      detail: getTypeDescription(t),
      boost: t.startsWith(prefix) ? 2 : 0,
    }));
    return { from, options, filter: true };
  }

  const spacingValueMatch = beforeChar.match(
    /"(?:mt|mb|ml|mr)"\s*:\s*"([^"]*)$/
  );
  if (spacingValueMatch) {
    const prefix = spacingValueMatch[1];
    const from = pos - prefix.length;
    const options: Completion[] = spacingValues.map(v => ({
      label: v,
      type: 'enum',
      detail: 'spacing token',
    }));
    return { from, options, filter: true };
  }

  const alertTypeMatch = beforeChar.match(/"type"\s*:\s*"([^"]*)$/) === null
    && beforeChar.match(/"type"\s*:\s*"([^"]*)$/i) === null
    ? null
    : null;
  void alertTypeMatch;

  const propValueMatch = beforeChar.match(/"(\w+)"\s*:\s*"([^"]*)$/);
  if (propValueMatch) {
    const propName = propValueMatch[1];
    const prefix = propValueMatch[2];
    const from = pos - prefix.length;

    if (['mt', 'mb', 'ml', 'mr'].includes(propName)) {
      return {
        from,
        options: spacingValues.map(v => ({
          label: v,
          type: 'enum' as const,
          detail: 'spacing token',
        })),
        filter: true,
      };
    }

    if (propName === 'align') {
      return {
        from,
        options: ['left', 'center', 'right'].map(v => ({
          label: v,
          type: 'enum' as const,
          detail: 'text alignment',
        })),
        filter: true,
      };
    }

    if (propName === 'keyboardType') {
      return {
        from,
        options: ['numeric', 'default', 'email-address', 'phone-pad'].map(v => ({
          label: v,
          type: 'enum' as const,
          detail: 'keyboard type',
        })),
        filter: true,
      };
    }
  }

  const insidePropsObject = isInsidePropsObject(doc, pos);
  if (insidePropsObject) {
    const componentType = getComponentTypeForPropsAt(doc, pos);
    if (componentType) {
      const schema = componentPropsSchemas[componentType] as PropSchema | undefined;
      if (schema?.properties) {
        const word = context.matchBefore(/[\w]*/) || { from: pos, to: pos, text: '' };
        const existingKeys = getExistingKeysInObject(doc, pos);
        const required = (schema.required as readonly string[] | undefined) ?? [];

        const options: Completion[] = Object.entries(schema.properties)
          .filter(([key]) => !existingKeys.has(key))
          .map(([key, def]) => {
            const isRequired = required.includes(key);
            const detail = getPropDetail(key, def as PropDef);
            return {
              label: `"${key}"`,
              displayLabel: key,
              type: isRequired ? 'property' : 'variable',
              detail: `${detail}${isRequired ? ' (required)' : ''}`,
              boost: isRequired ? 10 : 0,
              apply: buildPropApply(key, def as PropDef),
            };
          });

        if (options.length === 0) return null;
        return { from: word.from, options, filter: true };
      }
    }
  }

  const insideComponentObject = isInsideComponentObject(doc, pos);
  if (insideComponentObject) {
    const word = context.matchBefore(/[\w]*/) || { from: pos, to: pos, text: '' };
    const existingKeys = getExistingKeysInObject(doc, pos);

    const options: Completion[] = componentStructureKeys
      .filter(key => !existingKeys.has(key))
      .map(key => {
        const detail = key === 'type' ? 'component type (required)'
          : key === 'props' ? 'component properties (required)'
          : 'conditional visibility';
        return {
          label: `"${key}"`,
          displayLabel: key,
          type: 'property',
          detail,
          boost: key === 'type' ? 10 : key === 'props' ? 9 : 0,
          apply: key === 'type' ? '"type": ""'
            : key === 'props' ? '"props": {}'
            : '"visible": { "rule": {} }',
        };
      });

    if (options.length === 0) return null;
    return { from: word.from, options, filter: true };
  }

  const insideTopLevel = isInsideTopLevelObject(doc, pos);
  if (insideTopLevel) {
    const word = context.matchBefore(/[\w]*/) || { from: pos, to: pos, text: '' };
    const existingKeys = getExistingKeysInObject(doc, pos);

    const options: Completion[] = screenTopLevelKeys
      .filter(key => !existingKeys.has(key))
      .map(key => ({
        label: `"${key}"`,
        displayLabel: key,
        type: 'property',
        detail: key === 'id' ? 'screen identifier (required)'
          : key === 'body' ? 'component list (required)'
          : key === 'context' ? 'interpolation data'
          : key === 'header' ? 'screen header component'
          : 'screen footer component',
        boost: key === 'id' ? 10 : key === 'body' ? 9 : 0,
        apply: key === 'id' ? '"id": ""'
          : key === 'body' ? '"body": []'
          : key === 'context' ? '"context": {}'
          : key === 'header' ? '"header": { "type": "", "props": {} }'
          : '"footer": { "type": "", "props": {} }',
      }));

    if (options.length === 0) return null;
    return { from: word.from, options, filter: true };
  }

  return null;
}

function buildPropApply(key: string, def: PropDef): string {
  if (def.type === 'boolean') return `"${key}": false`;
  if (def.type === 'number') return `"${key}": 0`;
  if (def.type === 'array') return `"${key}": []`;
  if (def.type === 'object') return `"${key}": {}`;
  if (def.enum) return `"${key}": ""`;
  return `"${key}": ""`;
}

function isInsidePropsObject(doc: string, pos: number): boolean {
  const before = doc.slice(0, pos);
  let depth = 0;

  for (let i = before.length - 1; i >= 0; i--) {
    if (before[i] === '}') depth++;
    if (before[i] === '{') {
      depth--;
      if (depth < 0) {
        const preceding = before.slice(Math.max(0, i - 30), i).trim();
        return /["']props["']\s*:\s*$/.test(preceding);
      }
    }
  }
  return false;
}

function getComponentTypeForPropsAt(doc: string, pos: number): string | null {
  const before = doc.slice(0, pos);
  let depth = 0;

  for (let i = before.length - 1; i >= 0; i--) {
    if (before[i] === '}') depth++;
    if (before[i] === '{') {
      depth--;
      if (depth < 0) {
        const outerStart = before.lastIndexOf('{', i - 1);
        if (outerStart >= 0) {
          const outerChunk = doc.slice(outerStart, outerStart + 300);
          const typeMatch = outerChunk.match(/"type"\s*:\s*"([^"]+)"/);
          if (typeMatch && (knownTypes as readonly string[]).includes(typeMatch[1])) {
            return typeMatch[1];
          }
        }
        break;
      }
    }
  }
  return null;
}

function isInsideComponentObject(doc: string, pos: number): boolean {
  const before = doc.slice(0, pos);
  let depth = 0;

  for (let i = before.length - 1; i >= 0; i--) {
    if (before[i] === '}' || before[i] === ']') depth++;
    if (before[i] === '{' || before[i] === '[') {
      depth--;
      if (depth < 0) {
        if (before[i] === '[') {
          const preceding = before.slice(Math.max(0, i - 30), i).trim();
          return /["']body["']\s*:\s*$/.test(preceding);
        }
        const preceding = before.slice(Math.max(0, i - 30), i).trim();
        if (/,\s*$/.test(preceding) || /\[\s*$/.test(preceding)) {
          const bracketSearch = before.slice(0, i);
          const bracketPos = bracketSearch.lastIndexOf('[');
          if (bracketPos >= 0) {
            const beforeBracket = bracketSearch.slice(Math.max(0, bracketPos - 30), bracketPos).trim();
            return /["']body["']\s*:\s*$/.test(beforeBracket);
          }
        }
        return false;
      }
    }
  }
  return false;
}

function isInsideTopLevelObject(doc: string, pos: number): boolean {
  const before = doc.slice(0, pos);
  let depth = 0;

  for (let i = before.length - 1; i >= 0; i--) {
    if (before[i] === '}' || before[i] === ']') depth++;
    if (before[i] === '{' || before[i] === '[') {
      depth--;
      if (depth < 0) {
        if (before[i] === '{') {
          const preceding = before.slice(0, i).trim();
          return preceding.length === 0 || preceding === '';
        }
        return false;
      }
    }
  }
  return false;
}

function getExistingKeysInObject(doc: string, pos: number): Set<string> {
  const keys = new Set<string>();
  const before = doc.slice(0, pos);
  let depth = 0;
  let objStart = -1;

  for (let i = before.length - 1; i >= 0; i--) {
    if (before[i] === '}' || before[i] === ']') depth++;
    if (before[i] === '{' || before[i] === '[') {
      depth--;
      if (depth < 0) {
        objStart = i;
        break;
      }
    }
  }

  if (objStart < 0) return keys;

  let endBrace = doc.indexOf('}', pos);
  if (endBrace < 0) endBrace = doc.length;
  const objectContent = doc.slice(objStart, endBrace + 1);

  let keyMatch: RegExpExecArray | null;
  const keyRegex = /"([^"]+)"\s*:/g;
  while ((keyMatch = keyRegex.exec(objectContent)) !== null) {
    keys.add(keyMatch[1]);
  }

  return keys;
}

export function sduiAutocompletion() {
  return autocompletion({
    override: [sduiCompletionSource],
    activateOnTyping: true,
    maxRenderedOptions: 25,
    icons: true,
  });
}

