    await page.waitForTimeout(1000);
    await page.screenshot({ path: '.storybook/screenshots/autocomplete-trigger.png', fullPage: false });
  }

  await browser.close();
  console.log('Screenshots taken successfully');
})().catch(e => { console.error(e); process.exit(1); });
