  // Navigate to Storybook and click on SDUI VoucherDemo Form
  await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form');
  await page.waitForTimeout(4000);

  await page.screenshot({ path: '.storybook/screenshots/autocomplete-editor.png', fullPage: false });

  // Find the CodeMirror editor
  const editor = page.locator('.cm-content');
  if (await editor.count() > 0) {
    await editor.click();
    await page.keyboard.press('Control+Space');
    await page.waitForTimeout(1500);
    await page.screenshot({ path: '.storybook/screenshots/autocomplete-trigger.png', fullPage: false });
  } else {
    console.log('No .cm-content found');
  }

  await browser.close();
  console.log('Done');
})().catch(e => { console.error(e); process.exit(1); });
