const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1400, height: 900 } });

  await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form');
  await page.waitForTimeout(4000);

  // Click on the CodeMirror editor 
  const editor = page.locator('.cm-content');
  await editor.click();

  // Select all and clear, then type the beginning of a JSON to trigger autocomplete on type value
  await page.keyboard.press('Meta+a');
  await page.keyboard.press('Backspace');
  await page.waitForTimeout(200);

  // Type JSON beginning with type field to trigger component type autocomplete
  await page.keyboard.type('{\"type\": \"', { delay: 30 });
  await page.waitForTimeout(500);

  // Now type 'h' to filter to heading
  await page.keyboard.type('h', { delay: 50 });
  await page.waitForTimeout(1000);

  await page.screenshot({ path: '.storybook/screenshots/autocomplete-type-suggest.png', fullPage: false });

  await browser.close();
  console.log('Done');
})().catch(e => { console.error(e); process.exit(1); });
" 2>&1
